preToolUse.powershell:
param($input)
$payload = $input | ConvertFrom-Json
if ($payload.tool_name -ne 'run_sql') { exit 0 }
$dryRun = $payload.tool_input.dryRun
$sessionId = $payload.session_id
$stateDir = Join-Path $payload.cwd '.copilot-state'
$stateFile = Join-Path $stateDir "dryrun-$sessionId.flag"
# If this IS a dry run, create the flag file
if ($dryRun -eq $true) {
  if (-not (Test-Path $stateDir)) { New-Item -ItemType Directory -Path $stateDir | Out-Null }
  Set-Content -Path $stateFile -Value (Get-Date -Format 'o')
  exit 0
}
# If this is NOT a dry run, check that dry run was done first
if (-not (Test-Path $stateFile)) {
  Write-Output ('{"decision":"block","reason":"Dry-run required first. Call run_sql with dryRun=true to validate your SQL before executing for real. This protects your database from accidental changes."}')
  exit 1
}
exit 0
